function safeJsonParse(str) {
  try {
    return JSON.parse(str);
  } catch (e) {
    const match = String(str).match(/\{[\s\S]*\}/);
    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (e2) {
        return null;
      }
    }
    return null;
  }
}

const out = [];

for (const item of $input.all()) {
  // Resume data from Validate & Clean Parsed JSON
  const resume = item.json.resume_data || {};

  // JD Match response from Groq
  const raw =
    item.json.choices?.[0]?.message?.content || '{}';

  const match = safeJsonParse(raw) || {
    match_score: 0,
    matching_skills: [],
    missing_skills: [],
    relevant_experience: '',
    potential_concerns: [
      'AI matching failed - needs manual review'
    ],
    ai_summary: 'Automated matching failed.',
    hiring_recommendation: 'Possible Fit'
  };

  // --- Deterministic scoring engine ---
  // The AI's own numeric score has proven inconsistent across tests, so the
  // score and status below are computed with fixed rules from the candidate's
  // parsed skill list, NOT from the AI's match_score. The AI's text output
  // (ai_summary, matching_skills, missing_skills, potential_concerns) is
  // still used for narrative context, but the number and status are now
  // fully reproducible.
  //
  // EDIT THIS if the job description changes: each category should reflect
  // a "must-have" area from the JD, weights should sum to 100.
  const scoringCategories = [
    { label: 'Python',        keywords: ['python'],                    weight: 25 },
    { label: 'Framework',     keywords: ['django', 'flask'],           weight: 25 },
    { label: 'Database',      keywords: ['sql', 'postgresql', 'mysql'],weight: 15 },
    { label: 'Testing',       keywords: ['pytest', 'unittest'],        weight: 15 },
    { label: 'Version Control', keywords: ['git', 'github'],           weight: 10 },
    { label: 'Docker',        keywords: ['docker'],                    weight: 10 }
  ];

  const candidateSkillsText = (Array.isArray(resume.technical_skills)
    ? resume.technical_skills.join(' ')
    : String(resume.technical_skills || '')
  ).toLowerCase();

  let score = 0;
  const categoryHits = [];
  for (const cat of scoringCategories) {
    const hit = cat.keywords.some(kw => candidateSkillsText.includes(kw));
    if (hit) score += cat.weight;
    categoryHits.push(`${cat.label}: ${hit ? 'matched' : 'missing'}`);
  }
  score = Math.max(0, Math.min(100, score));

  // Recompute the recommendation label to match the deterministic score,
  // so "Recommendation" and "Application Status" can never contradict
  // each other again.
  if (score >= 80) {
    match.hiring_recommendation = 'Strong Fit';
  } else if (score >= 60) {
    match.hiring_recommendation = 'Possible Fit';
  } else {
    match.hiring_recommendation = 'Not a Fit';
  }

  let status;
  if (score >= 80) {
    status = 'Shortlisted';
  } else if (score >= 60) {
    status = 'Manual Review';
  } else {
    status = 'Rejected';
  }

  out.push({
    json: {
      // Resume Details
      name: resume.candidate_name || '',
      email: resume.email || '',
      phone: resume.phone || '',
      location: resume.location || '',
      experience_years:
        Number(resume.total_experience_years) || 0,
      skills: resume.technical_skills || [],
      education: resume.education || [],
      work_experience:
        resume.work_experience || [],

      // Email Metadata
      sender_name: item.json.sender_name || '',
      sender_email: item.json.sender_email || '',
      email_subject: item.json.email_subject || '',
      received_at: item.json.received_at || '',
      file_name: item.json.file_name || '',
      resume_file_url: item.json.resume_file_url || '',
      job_title: item.json.job_title || '',

      // Matching Results
      match_score: score,
      matching_skills:
        match.matching_skills || [],
      missing_skills:
        match.missing_skills || [],
      relevant_experience:
        match.relevant_experience || '',
      potential_concerns: [
        ...(match.potential_concerns || []),
        `Deterministic scoring breakdown: ${categoryHits.join(', ')}`
      ],
      ai_summary:
        match.ai_summary || '',
      hiring_recommendation:
        match.hiring_recommendation ||
        'Possible Fit',
      application_status: status
    },
    binary: item.binary
  });
}

return out;

